// // This T-flip-flop toggles its output (Q) on the falling edge of the clock when T=1 and CE=1. If CE=0, the output remains unchanged regardless of the value of T.
module t_flip_flop(  
    input wire clk,  
    input wire CE,  
    input wire T,  
    output reg Q  
);  

    always @(posedge clk) begin  
        if (CE) begin  
            if (T)  
                Q <= ~Q;  
        end  
    end  

    initial begin  
        Q = 0;  
    end  
endmodule
